!function(){"use strict";document.addEventListener("DOMContentLoaded",function(){const t=document.querySelectorAll(".luxury-product-card, .editorial-section, .woocommerce ul.products li.product");if(!t.length||!("IntersectionObserver"in window))return;const e=new IntersectionObserver(function(t,e){t.forEach(function(t){t.isIntersecting&&(t.target.classList.add("fade-in-up"),e.unobserve(t.target))})},{threshold:.1,rootMargin:"50px 0px"});t.forEach(function(t){t.style.opacity="0",t.style.transform="translateY(30px)",e.observe(t)})})}();